import React, { useState, useRef, useCallback, useMemo, type ReactNode } from 'react';
import { View, StyleSheet, type LayoutChangeEvent } from 'react-native';
import GridContext, { arrangeIntoRows } from './GridContext';

export interface IKitsGridProps {
  /** Total number of columns in the grid (default 12) */
  columns?: number;
  /** Gap between columns in pixels (default 0) */
  columnGap?: number;
  /** Gap between rows in pixels (default 0) */
  rowGap?: number;
  children: ReactNode;
}

interface RegistryEntry {
  colSpan: number;
  order: number;
}

/**
 * Pure React Native grid container.
 *
 * Measures its own width via onLayout, then calculates pixel widths
 * for each registered KitsGridItem based on colSpan / numColumns.
 *
 * Children communicate via GridContext — KitsGridItem does NOT need
 * to be a direct child of KitsGrid.
 */
const KitsGrid = ({
  columns = 12,
  columnGap = 0,
  rowGap = 0,
  children,
}: IKitsGridProps) => {
  const [containerWidth, setContainerWidth] = useState(0);
  const registryRef = useRef(new Map<string, RegistryEntry>());
  const orderCounterRef = useRef(0);
  const [version, setVersion] = useState(0);

  const registerItem = useCallback((id: string, colSpan: number) => {
    const existing = registryRef.current.get(id);
    if (existing) {
      if (existing.colSpan !== colSpan) {
        existing.colSpan = colSpan;
        setVersion(v => v + 1);
      }
    } else {
      registryRef.current.set(id, {
        colSpan,
        order: orderCounterRef.current++,
      });
      setVersion(v => v + 1);
    }
  }, []);

  const unregisterItem = useCallback((id: string) => {
    if (registryRef.current.has(id)) {
      registryRef.current.delete(id);
      setVersion(v => v + 1);
    }
  }, []);

  // Calculate pixel widths for every registered item
  const itemWidths = useMemo(() => {
    const widths = new Map<string, number>();
    if (containerWidth <= 0) return widths;

    const items = Array.from(registryRef.current.entries()).sort(
      (a, b) => a[1].order - b[1].order,
    );
    if (items.length === 0) return widths;

    const ids = items.map(([id]) => id);
    const colSpans = items.map(([_, data]) =>
      Math.min(data.colSpan, columns),
    );

    const rows = arrangeIntoRows(colSpans, columns);

    for (const indices of Object.values(rows)) {
      const itemsInRow = indices.length;
      const totalGapWidth = columnGap * (itemsInRow - 1);
      const availableWidth = containerWidth - totalGapWidth;

      for (const idx of indices) {
        const width = Math.max(
          0,
          Math.floor((availableWidth * colSpans[idx]) / columns),
        );
        widths.set(ids[idx], width);
      }
    }

    return widths;
    // `version` triggers recalc when registry changes
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [containerWidth, version, columns, columnGap]);

  const getItemWidth = useCallback(
    (id: string) => itemWidths.get(id),
    [itemWidths],
  );

  const contextValue = useMemo(
    () => ({
      registerItem,
      unregisterItem,
      getItemWidth,
      containerWidth,
      numColumns: columns,
      columnGap,
      rowGap,
    }),
    [registerItem, unregisterItem, getItemWidth, containerWidth, columns, columnGap, rowGap],
  );

  const handleLayout = useCallback((event: LayoutChangeEvent) => {
    const width = Math.floor(event.nativeEvent.layout.width);
    setContainerWidth(prev => (prev !== width ? width : prev));
  }, []);

  return (
    <GridContext.Provider value={contextValue}>
      <View
        style={[styles.container, { columnGap, rowGap }]}
        onLayout={handleLayout}
      >
        {children}
      </View>
    </GridContext.Provider>
  );
};

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    width: '100%',
  },
});

export default KitsGrid;
